args.query:
SELECT "Patient_description" AS participant_barcode, "Sex" AS sex, "Histological_type" AS histological_type, "Cancer_Type_Acronym" AS cancer_type
FROM clinical_info
WHERE "Cancer_Type_Acronym" = 'BRCA' AND "Sex" = 'FEMALE' AND "Histological_type" IS NOT NULL;

